      },
      {
        "name": "Event Publisher",
        "responsibility": "Captures write-side changes and publishes them for read model projection. At ~500 orders/day, a simple outbox table with a polling publisher or Postgres LISTEN/NOTIFY is sufficient. No Kafka needed at this scale.",
        "boundaries": "Sits between write model and projection engine. Guarantees at-least-once delivery. Does not transform data — publishes raw domain events."
      },
      {
        "name": "Projection Engine",
        "responsibility": "Subscribes to domain events and updates the four denormalized read models. Each projector is a pure function: event → read model mutation. Handles idempotency via event sequence tracking. Can be rebuilt from scratch by replaying events.",
        "boundaries": "Owns the transformation logic from normalized events to denormalized views. Stateless except for its checkpoint cursor. One projector per read model."
      },
      {
        "name": "Read Model Store",
        "responsibility": "Stores four pre-computed, query-optimized denormalized tables/materialized views: (1) orders_by_status, (2) delivery_success_rates, (3) transit_time_by_zone, (4) courier_performance. Each is shaped exactly for its dashboard widget — single-table scans, no joins.",
        "boundaries": "Read-only from the dashboard's perspective. Written to only by the Projection Engine. Can use a separate database or schema within the same Postgres instance."
      },
      {
        "name": "Query API (Read Side)",
        "responsibility": "Serves the operations dashboard. Routes queries to the appropriate read model table. Responses are sub-100ms because each query hits a single pre-computed table with appropriate indexes.",
        "boundaries": "No access to write-side tables. No business logic — pure data retrieval with optional filtering/pagination."
      },
      {
        "name": "Operations Dashboard",
        "responsibility": "Frontend consuming the Query API. Displays orders by status, delivery success rates, average transit time by zone, and courier performance rankings.",
        "boundaries": "Accepts eventual consistency (seconds-level staleness). Displays a 'last updated' timestamp per widget."
      }
    ],
    "interfaces": [
      {
        "from": "Write Model",
        "to": "Event Publisher",
        "contract": "Transactional outbox: on each write, an event record is inserted into an `domain_events` outbox table within the same transaction. Schema: {event_id, aggregate_id, event_type, payload_json, created_at, published_at}",
        "coupling_type": "loose — outbox pattern decouples write transaction from event delivery"
      },
      {
        "from": "Event Publisher",
        "to": "Projection Engine",
        "contract": "Ordered event stream per aggregate. Events: OrderCreated{order_id, status, zone, courier_id, created_at}, OrderStatusChanged{order_id, old_status, new_status, changed_at}, DeliveryCompleted{order_id, zone, courier_id, transit_time_hours, success: bool, completed_at}",
        "coupling_type": "loose — async, at-least-once, idempotent consumers"
      },
      {
        "from": "Projection Engine",
        "to": "Read Model Store",
        "contract": "Direct SQL upserts into four denormalized tables. Each projector owns exactly one table. Projectors track their last processed event_id for checkpointing.",
        "coupling_type": "tight — projector is tightly coupled to its read model schema (intentional, co-deployed)"
      },
      {
        "from": "Query API",
        "to": "Read Model Store",
        "contract": "SELECT queries only. No joins. Filtering by time range, zone, courier_id, status. Pagination via cursor. Response < 100ms p99.",
        "coupling_type": "tight — query API is shaped to the read model (intentional)"
      },
      {
        "from": "Operations Dashboard",
        "to": "Query API",
        "contract": "REST/GraphQL endpoints: GET /dashboard/orders-by-status, GET /dashboard/delivery-rates?zone=&period=, GET /dashboard/transit-times?zone=, GET /dashboard/courier-rankings?period=&limit=",
        "coupling_type": "loose — standard HTTP API"
      }
    ],
    "data_flow": "Order mutations enter the Write Model and are persisted to the normalized 12-table schema. In the same transaction, a domain event is written to the outbox table. The Event Publisher polls the outbox (or uses LISTEN/NOTIFY) every 1-5 seconds, picks up unpublished events, and delivers them to the Projection Engine. Each of the four projectors processes relevant events and upserts into its dedicated denormalized read table. The Query API serves the dashboard by reading from these pre-computed tables — zero joins, sub-100ms responses. At 500 orders/day, the entire pipeline adds < 5 seconds of end-to-end latency from write to dashboard visibility.",
    "patterns_used": [
      {
        "pattern": "CQRS (Command Query Responsibility Segregation)",
        "rationale": "The core pattern. Read and write workloads have fundamentally different shapes: writes need normalized integrity across 12 tables; reads need denormalized, pre-aggregated views. Separating them lets each side optimize independently."
      },
      {
        "pattern": "Transactional Outbox",
        "rationale": "Guarantees reliable event publishing without distributed transactions. The event is written atomically with the business data. Avoids dual-write problems. At 500 events/day, the outbox table stays tiny."
      },
      {
        "pattern": "Denormalized Read Models (Materialized Views)",
        "rationale": "Pre-computing the 12-table joins at write time (when load is low — 500/day) rather than at read time (when load is high — every dashboard refresh) is the fundamental performance win."
      },
      {
        "pattern": "Projector per View",
        "rationale": "Each dashboard widget gets its own projector and table. This isolates concerns: courier performance projector logic doesn't affect transit time projector. Each can be rebuilt independently."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Order Management (Write Side)",
        "classification": "core",
        "aggregates": [
          "Order (root: order_id — encapsulates status lifecycle, delivery assignment, zone routing)",
          "Courier (root: courier_id — tracks availability and assignment history)"
        ]
      },
      {
        "name": "Operations Reporting (Read Side)",
        "classification": "supporting",
        "aggregates": [
          "Note: Read models are NOT aggregates — they are query-optimized projections with no invariants to protect. They are flat denormalized tables: orders_by_status, delivery_success_rates, transit_time_by_zone, courier_performance."
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Operations Reporting",
        "relationship": "Customer-Supplier via domain events. Order Management publishes events; Operations Reporting consumes and projects. The read side conforms to the write side's event schema (Conformist relationship — acceptable because both are owned by the same team)."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "CQRS with denormalized read models instead of optimizing existing queries",
      "gains": "Dashboard queries drop from 30-60s to <100ms. Read and write models evolve independently. New dashboard views can be added without touching the write schema. Read models can be rebuilt from events at any time.",
      "sacrifices": "Eventual consistency — dashboard data may be seconds stale (acceptable for operations dashboard). Additional infrastructure: outbox table, publisher process, projector process. More code to maintain (projectors). Developers must understand two data paths.",
      "alternatives_considered": [
        "Materialized views in Postgres — simpler but refresh is expensive on 50M rows with 12-table joins; refresh would still take 10-30s and locks the view during refresh",
        "Adding indexes and query optimization — diminishing returns on 12-table joins at 50M scale; would help marginally but not achieve sub-second",
        "Read replicas — doesn't solve the fundamental problem of expensive joins; just moves the load to another server",
        "Pre-aggregation via cron jobs — achieves similar result but less maintainable, no clear event-driven update path, stale data measured in minutes not seconds"
      ]
    },
    {
      "decision": "Transactional outbox over event sourcing",
      "gains": "Keep the existing normalized write model unchanged. No need to refactor to event-sourced aggregates. Much simpler mental model. The team's existing ORM and write patterns work as-is.",
      "sacrifices": "Cannot replay the full event history from day one (only from when outbox was added). Outbox adds a small overhead to each write transaction. Need a process to clean up old outbox entries.",
      "alternatives_considered": [
        "Full event sourcing — massive overkill for 500 writes/day; would require rewriting the entire write side for minimal benefit",
        "Change Data Capture (Debezium on WAL) — viable alternative but adds infrastructure dependency (Kafka Connect, Debezium); better suited if write volume grows to 50K+/day",
        "Synchronous projection on write — viable at 500/day and even simpler; considered as Phase 1 approach (see implementation guidance)"
      ]
    },
    {
      "decision": "Same database, separate schema for read models (not a separate database)",
      "gains": "No cross-database infrastructure. Simpler deployment and operations. Backup/restore is unified. At 500 writes/day and modest read load, a single Postgres instance handles both easily.",
      "sacrifices": "Read and write compete for the same database resources (CPU, memory, I/O). Cannot scale read side independently.",
      "alternatives_considered": [
        "Separate read database (Postgres replica or dedicated instance) — warranted if dashboard query load is very high or read model grows to billions; overkill now",
        "Elasticsearch for read models — good for full-text search but these are structured aggregation queries; Postgres handles them well with proper denormalization",
        "Redis for read models — sub-millisecond reads but loses SQL querying flexibility; could be a future optimization for the most-hit widgets"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Read model schemas",
      "evolution_path": "Each read model table can be independently reshaped, dropped, and rebuilt from events. Adding a new dashboard widget means adding one new projector and one new table — zero impact on write side or other read models."
    },
    {
      "area": "Event publishing mechanism",
      "evolution_path": "Start with outbox polling. If latency requirements tighten or write volume grows, swap to CDC (Debezium) without changing the write model or projectors — only the Event Publisher component changes."
    },
    {
      "area": "Read model storage engine",
      "evolution_path": "Start with same-database Postgres tables. If query patterns shift (e.g., free-text search, time-series analytics), individual read models can migrate to specialized stores (Elasticsearch, TimescaleDB) independently."
    },
    {
      "area": "Projection strategy",
      "evolution_path": "Start with synchronous projection (update read model in the same request as the write). If write latency becomes a concern at higher volumes, switch to async projection with the outbox — the projector code stays the same, only the trigger mechanism changes."
    }
  ],

  "rigidity_points": [
    {
      "area": "Domain event schema",
      "reason": "Once projectors depend on event schemas, changing event structure requires coordinated updates to both the publisher and all consuming projectors. Use explicit versioning from day one (e.g., OrderCreated_v1) to enable evolution without breaking existing projectors."
    },
    {
      "area": "Write-side normalized schema",
      "reason": "The existing 12-table schema is intentionally left unchanged. CQRS works around its complexity rather than refactoring it. This is a feature — it preserves write-side data integrity — but means the write model remains hard to query directly."
    },
    {
      "area": "Consistency model",
      "reason": "The dashboard is eventually consistent by design. If a future requirement demands real-time consistency (e.g., an order just placed must appear instantly on the dashboard), this requires architectural changes to the projection pipeline."
    }
  ],

  "risks": [
    {
      "risk": "Backfill complexity: 50M existing records need to be projected into the new read models before the dashboard can switch over",
      "severity": "high",
      "mitigation": "Write a one-time backfill script that reads from the normalized tables and populates the read models directly (not via events). Run during a maintenance window. Verify row counts and checksums. After backfill, the projectors handle incremental updates going forward."
    },
    {
      "risk": "Projector bugs causing read model drift from write model",
      "severity": "medium",
      "mitigation": "Implement a periodic reconciliation job that compares read model aggregates against source-of-truth queries on the write side. Alert on drift > threshold. Make read models rebuildable — every projector must support a full rebuild mode."
    },
    {
      "risk": "Team unfamiliarity with CQRS leading to over-engineering",
      "severity": "medium",
      "mitigation": "Start with the simplest possible implementation: synchronous projectors called directly from the write path (no outbox, no async, no message broker). Evolve to async only when needed. Avoid event sourcing entirely."
    },
